package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElementVerwerker;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import lombok.AllArgsConstructor;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_BEDRAG_KEY;

@AllArgsConstructor
public class PrestatiesDisponibiliteit {

    private final LoonElementVerwerker loonElementVerwerker;
    private final Disponibiliteit disponibiliteit;

    public void verwerk(
            LoonElementManager manager, LoonCodeManager loonCodeManager, RekenTijd rekenTijd,
            AardKodeExtensie looncodeGewoonLoon, PrestatieSamenvatting samenvatting, BigDecimal prestatieNoemer, Opper opper,
            MoneyMap<AardKodeExtensie> carryoverMap) {
        BasisDispo basisDispo = bepaalBasisDispo(manager, rekenTijd, looncodeGewoonLoon, opper);
        Money bedragDispo = basisDispo.getBedragDispo();
        Money bedragDispo100 = basisDispo.getBedragDispo100();

        GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        if (samenvatting.getTellerDisponibiliteit60().signum() > 0) {
            BigDecimal percentageDispo60 = disponibiliteit.bepaalPercentage60(opper, rekenTijd);
            if (samenvatting.getTellerDisponibiliteit60NBV().signum() > 0) {
                Money bedrag = bedragDispo.multiply(samenvatting.getTellerDisponibiliteit60NBV()).multiply(percentageDispo60).divide(prestatieNoemer);
                bedrag = bedrag.add(berekenBedragVoorTeller(bedragDispo100, samenvatting.getTellerDisponibiliteit60NBV(), prestatieNoemer));
                AardKodeExtensie looncodeDispo60ZonderBV = gewoonLoon.createDispo60ZonderBV();
                loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeDispo60ZonderBV, bedrag, rekenTijd, carryoverMap);
            }
            if (samenvatting.getTellerDisponibiliteit60BV().signum() > 0) {
                Money bedrag = bedragDispo.multiply(samenvatting.getTellerDisponibiliteit60BV()).multiply(percentageDispo60).divide(prestatieNoemer);
                bedrag = bedrag.add(berekenBedragVoorTeller(bedragDispo100, samenvatting.getTellerDisponibiliteit60BV(), prestatieNoemer));
                AardKodeExtensie looncodeDispo60MetBV = gewoonLoon.createDispo60MetBV();
                loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeDispo60MetBV, bedrag, rekenTijd, carryoverMap);
            }
        }
        if (samenvatting.getTellerDisponibiliteit100().signum() > 0) {
            Money bedrag = berekenBedragVoorTeller(bedragDispo.add(bedragDispo100), samenvatting.getTellerDisponibiliteit100(), prestatieNoemer);
            AardKodeExtensie looncodeDispo100 = gewoonLoon.createDispo100();
            loonElementVerwerker.verwerkTotLoonElement(opper, manager, looncodeDispo100, bedrag, rekenTijd, carryoverMap);
        }
    }

    public BasisDispo bepaalBasisDispo(LoonElementManager manager, RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, Opper opper) {
        return bepaalBasisDispo(manager, rekenTijd, looncodeGewoonLoon, opper, BASIS_BEDRAG_KEY);
    }

    public BasisDispo bepaalBasisDispo(LoonElementManager manager, RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, Opper opper, RekenBrutoKey basisKey) {
        Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
        BasisDispo basisDispo = new BasisDispo(Money.ZERO, Money.ZERO);
        for (LoonElement element : loonElementen) {
            AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
            if (aardKodeExtensie.getOmzettenWachtweddeDispo()) {
                basisDispo = basisDispo.add(bepaalBasisDispoLoonElement(element, rekenTijd, looncodeGewoonLoon, opper, basisKey));
            }
        }
        return basisDispo;
    }

    private BasisDispo bepaalBasisDispoLoonElement(
            LoonElement element, RekenTijd rekenTijd, AardKodeExtensie looncodeGewoonLoon, Opper opper, RekenBrutoKey basisKey) {
        AardKodeExtensie aardKodeExtensie = element.getAardKodeExtensie();
        DispoType dispoType = disponibiliteit.bepaalDispoType(aardKodeExtensie, looncodeGewoonLoon, opper, rekenTijd);

        if (dispoType == DispoType.DISPO_100) {
            return new BasisDispo(Money.ZERO, element.getPropertyMoney(basisKey));
        } else if (dispoType == DispoType.DISPO_60) {
            return new BasisDispo(element.getPropertyMoney(basisKey), Money.ZERO);
        } else {
            return new BasisDispo(Money.ZERO, Money.ZERO);
        }
    }

    private Money berekenBedragVoorTeller(Money bedrag, BigDecimal teller, BigDecimal noemer) {
        return bedrag.multiply(teller).divide(noemer);
    }
}
